  ('disabled-0a2fc18c-moex-00143', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-112-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '下列何者將導致生產可能曲線向外移動？', '["失業率下降", "乾旱造成農業單位面積生產力降低", "生產要素的生產效率提高", "將資源從一商品的生產轉移到另一商品"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "ec91441b2ca1", "answer_pdf_sha1": "79ebb3660238", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "405", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL)
